=You are a customer support researcher. Answer the question using only public, authoritative web sources such as official product or API documentation, public standards, vendor status and changelog pages, and regulatory or help-center pages. Give specific, accurate facts and cite the source for every claim. If sources conflict or the answer is uncertain, say so plainly. Do not invent behavior that is not documented.

Question:
{{ ($json.Question ?? '').toString().trim() }}

Context:
{{ ($json.Context ?? '').toString().trim() || 'None provided.' }}

parameters.jsCode:
// You.com "research" returns: { output: { content, content_type, sources: [{url,title,snippets}] } }
// This node turns that into an HTML email body (Markdown -> HTML), a plain-text fallback,
// a subject, and the recipient, so Gmail can save it as a draft for a human to review and send.
const out = ($json.output ?? {});
const answerRaw = (out.content ?? '').toString().trim()
  || 'You.com returned no answer. Please research this question manually before replying.';
const sources = Array.isArray(out.sources) ? out.sources : [];

const cfg = $('Prepare Research Request').item.json;
const question = (cfg.question ?? '').toString().trim();
const customerEmail = (cfg.customerEmail ?? '').toString().trim();

// Escape HTML so answer text and titles are safe inside the email body.
const esc = (s) => (s ?? '').toString()
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

// Light Markdown -> HTML for one line: bold, inline code, and [[n]]/[n] citation markers
// become superscript links that point at the matching source in the Sources list.
const inlineHtml = (line) => {
  let h = esc(line);
  h = h.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  h = h.replace(/`([^`]+?)`/g, '<code>$1</code>');
  h = h.replace(/\[\[(\d+)\]\]/g, (_m, n) => '<sup><a href="#src-' + n + '">[' + n + ']</a></sup>');
  h = h.replace(/(^|[^\[])\[(\d+)\]([^\]]|$)/g, (_m, a, n, b) => a + '<sup><a href="#src-' + n + '">[' + n + ']</a></sup>' + b);
  return h;
};

// Split the answer into paragraphs and simple bullet lists.
const blocks = answerRaw.split(/\n{2,}/);
let answerHtml = '';
for (const block of blocks) {
  const lines = block.split('\n').map((l) => l.trim()).filter(Boolean);
  if (!lines.length) continue;
  const isList = lines.every((l) => /^[-*]\s+/.test(l));
  if (isList) {
    answerHtml += '<ul>' + lines.map((l) => '<li>' + inlineHtml(l.replace(/^[-*]\s+/, '')) + '</li>').join('') + '</ul>';
  } else {
    answerHtml += '<p>' + lines.map(inlineHtml).join('<br>') + '</p>';
  }
}

// Numbered, linked Sources list. Anchor ids match the citation markers above.
let sourcesHtml = '';
let sourcesText = '';
if (sources.length) {
  sourcesHtml = '<h3>Sources</h3><ol>';
  sources.forEach((s, i) => {
    const n = i + 1;
    const url = (s && s.url ? s.url : '').toString().trim();
    const title = ((s && s.title ? s.title : '') || url || ('Source ' + n)).toString().trim();
    sourcesHtml += '<li id="src-' + n + '"><a href="' + esc(url) + '">' + esc(title) + '</a></li>';
    sourcesText += '[' + n + '] ' + title + ' - ' + url + '\n';
  });
  sourcesHtml += '</ol>';
} else {
  sourcesHtml = '<p><em>You.com returned no sources. Verify the answer before sending.</em></p>';
  sourcesText = 'No sources were returned. Verify the answer before sending.\n';
}

const note = '<p style="color:#666;font-size:12px">Draft prepared from live public web sources by You.com. '
  + 'A support agent should verify the sources and edit before sending. This draft was not sent automatically.</p>';

const htmlBody = '<div>' + answerHtml + sourcesHtml + note + '</div>';
const textBody = answerRaw + '\n\nSources:\n' + sourcesText
  + '\n(Draft prepared from public web sources by You.com. Verify before sending. Not sent automatically.)';

const subjectQ = question.length > 60 ? (question.slice(0, 57) + '...') : question;
const subject = subjectQ ? ('Re: ' + subjectQ) : 'Re: your support question';

return {
  htmlBody,
  textBody,
  subject,
  sendTo: customerEmail,
  sourceCount: sources.length,
};

